1	import {
2		BLOCK_ELEMENTS_SET,
3		BLOCK_ELEMENTS_SELECTOR,
4		BLOCK_LEVEL_ELEMENTS,
5		PRESERVE_ELEMENTS,
6		INLINE_ELEMENTS,
7		ALLOWED_ATTRIBUTES,
8		ALLOWED_ATTRIBUTES_DEBUG,
9		ALLOWED_EMPTY_ELEMENTS,
10		TAILWIND_COLORS,
11		TAILWIND_SPECIAL,
12		TW_COLOR_CLASS_RE,
13		TW_SPECIAL_CLASS_RE,
14		TW_ARBITRARY_RE
15	} from './constants';
16	
17	import { DefuddleMetadata } from './types';
18	import { mathRules } from './elements/math';
19	import { wrapRawLatexDelimiters } from './elements/math.base';
20	import { codeBlockRules } from './elements/code';
21	import { headingRules, removePermalinkAnchors, isPermalinkAnchor } from './elements/headings';
22	import { imageRules } from './elements/images';
23	import { isElement, isTextNode, isCommentNode, isSVGElement, getComputedStyle, logDebug } from './utils';
24	import { transferContent, isDirectTableChild, getClassName } from './utils/dom';
25	
26	// Module-level debug flag, set by standardizeContent for child functions
27	let _debug = false;
28	
29	// Element standardization rules
30	// Maps selectors to their target HTML element name
31	interface StandardizationRule {
32		selector: string;
33		element: string;
34		/** Cheap querySelector guard — skip the full selector scan if this returns null */
35		fastCheck?: string;
36		transform?: (el: Element, doc: Document) => Element;
37	}
38	
39	const ELEMENT_STANDARDIZATION_RULES: StandardizationRule[] = [
40		...mathRules,
41		...codeBlockRules,
42		...headingRules,
43		...imageRules,
44	
45		// Convert divs with paragraph role to actual paragraphs
46		{ 
47			selector: 'div[data-testid^="paragraph"], div[role="paragraph"]', 
48			element: 'p',
49			transform: (el: Element, doc: Document): Element => {
50				const p = doc.createElement('p');
51	
52				transferContent(el, p);
53	
54				// Copy allowed attributes
55				Array.from(el.attributes).forEach(attr => {
56					if (ALLOWED_ATTRIBUTES.has(attr.name)) {
57						p.setAttribute(attr.name, attr.value);
58					}
59				});
60				
61				return p;
62			}
63		},
64		// Convert divs with list roles to actual lists
65		{ 
66			selector: 'div[role="list"]', 
67			element: 'ul',
68			// Custom handler for list type detection and transformation
69			transform: (el: Element, doc: Document): Element => {
70				// First determine if this is an ordered list
71				const firstItem = el.querySelector('div[role="listitem"] .label');
72				const label = firstItem?.textContent?.trim() || '';
73				const isOrdered = label.match(/^\d+\)/);
74				
75				// Create the appropriate list type
76				const list = doc.createElement(isOrdered ? 'ol' : 'ul');
77				
78				// Process each list item
79				const items = el.querySelectorAll('div[role="listitem"]');
80				items.forEach(item => {
81					const li = doc.createElement('li');
82					const content = item.querySelector('.content');
83					
84					if (content) {
85						// Convert any paragraph divs inside content
86						const paragraphDivs = content.querySelectorAll('div[role="paragraph"]');
87						paragraphDivs.forEach(div => {
88							const p = doc.createElement('p');
89							transferContent(div, p);
90							div.replaceWith(p);
91						});
92						
93						// Convert any nested lists recursively
94						const nestedLists = content.querySelectorAll('div[role="list"]');
95						nestedLists.forEach(nestedList => {
96							const firstNestedItem = nestedList.querySelector('div[role="listitem"] .label');
97							const nestedLabel = firstNestedItem?.textContent?.trim() || '';
98							const isNestedOrdered = nestedLabel.match(/^\d+\)/);
99							
100							const newNestedList = doc.createElement(isNestedOrdered ? 'ol' : 'ul');
101							
102							// Process nested items
