794:function removeEmptyElements(element: Element): void {
795:	let removedCount = 0;
796:
797:	const isEmptyElement = (el: Element): boolean => {
798:		if (ALLOWED_EMPTY_ELEMENTS.has(el.tagName.toLowerCase())) return false;
799:
800:		// Special case: divs that only contain spans with commas
801:		if (el.tagName === 'DIV') {
802:			const children = el.children;
803:			if (children.length > 0) {
804:				let allCommaSpans = true;
805:				for (let i = 0; i < children.length; i++) {
806:					const child = children[i];
807:					if (child.tagName !== 'SPAN') { allCommaSpans = false; break; }
808:					const content = child.textContent?.trim() || '';
809:					if (content !== ',' && content !== '' && content !== ' ') { allCommaSpans = false; break; }
810:				}
811:				if (allCommaSpans) return true;
812:			}
813:		}
814:
815:		const textContent = el.textContent || '';
816:		if (textContent.trim().length > 0 || textContent.includes('\u00A0')) return false;
817:
818:		// Check if element has no meaningful children (no element children, only whitespace text)
819:		if (!el.hasChildNodes()) return true;
820:		const childNodes = el.childNodes;
821:		for (let i = 0; i < childNodes.length; i++) {
822:			const node = childNodes[i];
823:			// <br> elements are non-content spacers — treat them as empty
824:			if (isElement(node) && node.tagName.toLowerCase() === 'br') continue;
825:			if (!isTextNode(node)) return false;
826:			const nodeText = node.textContent || '';
827:			if (nodeText.trim().length > 0 || nodeText.includes('\u00A0')) return false;
828:		}
829:		return true;
830:	};
831:
832:	// Process deepest-first in a single pass by reversing the element list
833:	// (querySelectorAll returns document order, reverse gives deepest last → first)
834:	const allElements = Array.from(element.querySelectorAll('*')).reverse();
835:	for (const el of allElements) {
836:		if (el.parentNode && isEmptyElement(el)) {
837:			el.remove();
838:			removedCount++;
839:		}
840:	}
841:
842:	logDebug(_debug, 'Removed empty elements:', removedCount);
843:}
